<svg viewBox="0 0 700 320" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Roadmap der britischen Tokenisierungs-Taskforce</text>
  <g font-family="sans-serif">
    <line x1="50" y1="150" x2="650" y2="150" stroke="#3f3f46" stroke-width="3"/>
